class Solution:
    def smallestValue(self, n: int) -> int:
        def prime_factors_sum(x):
            s = 0
            d = 2
            while d * d <= x:
                while x % d == 0:
                    s += d
                    x //= d
                d += 1
            if x > 1:
                s += x
            return s

        seen = set()
        while n not in seen:
            seen.add(n)
            next_n = prime_factors_sum(n)
            if next_n == n:
                break
            n = next_n
        return n

